{
  "name": "myproject",
  "version": "1.0.0",
  "private": true,
  "scripts": {
    "start": "concurrently \"npm run server\" \"npm run client\"",
    "server": "node server/index.js",
    "client": "vite --host 0.0.0.0 --port 3000"
  },
  "dependencies": {
    "@magicbell/react": "^4.0.0",
    "concurrently": "^8.2.2",
    "express": "^4.18.2",
    "jsonwebtoken": "^9.0.2",
    "magicbell-js": "^3.0.0",
    "react": "^18.2.0",
    "react-dom": "^18.2.0"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.2.1",
    "vite": "^5.1.0"
  }
}

const express = require('express');
const jwt = require('jsonwebtoken');
const { createProjectClient } = require('magicbell-js/project-client');

const app = express();
const PORT = 3001;

const ZEALT_RUN_ID = process.env.ZEALT_RUN_ID || '1';
const MAGICBELL_EMAIL = process.env.MAGICBELL_EMAIL || 'test@example.com';
const MAGICBELL_SECRET_KEY = process.env.MAGICBELL_SECRET_KEY || '';
const MAGICBELL_API_KEY = process.env.MAGICBELL_API_KEY || '';

// Derive the email with plus format
const emailParts = MAGICBELL_EMAIL.split('@');
const emailPrefix = emailParts[0];
const emailDomain = emailParts[1];
const derivedEmail = `${emailPrefix}+${ZEALT_RUN_ID}@${emailDomain}`;

const externalId = `user-${ZEALT_RUN_ID}`;

// Create MagicBell project client
const magicbellClient = createProjectClient({
  apiKey: MAGICBELL_API_KEY,
  apiSecret: MAGICBELL_API_KEY ? undefined : undefined,
  projectSecret: MAGICBELL_SECRET_KEY,
});

// Upsert user and send broadcast on startup
async function initialize() {
  try {
    console.log('Upserting user with external_id:', externalId, 'and email:', derivedEmail);

    // Upsert the user using the project client
    await magicbellClient.users.upsert({
      external_id: externalId,
      email: derivedEmail,
    });

    console.log('User upserted successfully');

    // Send a broadcast notification
    console.log('Sending broadcast notification...');
    await magicbellClient.broadcasts.create({
      title: `Test Notification ${ZEALT_RUN_ID}`,
      content: 'This is a test',
      recipients: [{ external_id: externalId }],
    });

    console.log('Broadcast notification sent successfully');
  } catch (err) {
    console.error('Initialization error:', err.message);
    console.error('Full error:', err);
  }
}

// GET /token endpoint - returns User JWT
app.get('/token', (req, res) => {
  const payload = {
    external_id: externalId,
    email: derivedEmail,
    iat: Math.floor(Date.now() / 1000),
  };

  const token = jwt.sign(payload, MAGICBELL_SECRET_KEY, {
    algorithm: 'HS256',
    expiresIn: '1h',
  });

  res.json({ token });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  initialize();
});

import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const root = createRoot(document.getElementById('root'));
root.render(<App />);

import React, { useState, useEffect } from 'react';
import { Provider, FloatingInbox } from '@magicbell/react';
import CustomNotificationItem from './CustomNotificationItem';

function App() {
  const [token, setToken] = useState(null);

  useEffect(() => {
    fetch('http://localhost:3001/token')
      .then((res) => res.json())
      .then((data) => {
        setToken(data.token);
      })
      .catch((err) => {
        console.error('Failed to fetch token:', err);
      });
  }, []);

  if (!token) {
    return <div>Loading...</div>;
  }

  return (
    <Provider apiKey={process.env.MAGICBELL_API_KEY || ''} userEmail="" userExternalId={`user-${process.env.ZEALT_RUN_ID || '1'}`} userKey={token}>
      <div style={{ padding: '20px' }}>
        <h1>MagicBell Notifications</h1>
        <FloatingInbox
          ItemComponent={CustomNotificationItem}
        />
      </div>
    </Provider>
  );
}

export default App;

import React from 'react';

function CustomNotificationItem({ notification }) {
  const handleMarkRead = async (e) => {
    e.stopPropagation();
    try {
      await notification.markAsRead();
    } catch (err) {
      console.error('Failed to mark notification as read:', err);
    }
  };

  return (
    <div className="custom-notification-item">
      <div className="custom-notification-title">
        {notification.title}
      </div>
      <div className="custom-notification-content">
        {notification.content}
      </div>
      {!notification.readAt && (
        <button className="custom-mark-read-btn" onClick={handleMarkRead}>
          Mark as read
        </button>
      )}
    </div>
  );
}

export default CustomNotificationItem;

