   * @internal
   */
  baseUrl?: string;

  /**
   * Override the socket server URL (used for testing/staging).
   * @internal
   */
  socketUrl?: string;

  /**
   * Enable or disable toast notifications.
   * @default true
   */
  toasts?: boolean;

  /**
   * Elements to render inside the provider.
   * @type {Element}
   */
  children?: any;
};
import { ensure } from "ensured";
import { createMagicBellContext } from "./internal/context/context.js";
import Context from "./internal/context/magicbell.context.js";
import { parseBoolean } from "./internal/lib/types.js";
import ToastContainer from "./toast-container.js";

function ContextProvider(props: Props) {
  return (
    <Context.Provider
      value={createMagicBellContext({
        token: props.token,
        baseUrl: props.baseUrl,
        socketUrl: props.socketUrl,
      })}
    >
      <>
        {props.children}
        {parseBoolean(props.toasts, true) ? <ToastContainer /> : null}
      </>
