"use client";
import * as React from "react";
import { useState } from "react";

/**
 * A floating version of the notification inbox, toggled by a button.
 *
 * Renders the inbox inside a floating panel positioned relative to a trigger.
 * Ideal for embedding in navigation bars or headers. Supports full customization
 * of placement, dimensions, trigger, and inbox content.
 *
 * @event { notification: Notification } mb-notification-click - Emitted when a notification item is clicked. Call event.preventDefault() to stop default navigation.
 */
type FloatingInboxProps = {
  /**
   * The width of the floating inbox panel in pixels.
   * @default 400
   */
  width?: FloatingUIProps["width"];

  /**
   * The height of the floating inbox panel in pixels.
   * @default 400
   */
  height?: FloatingUIProps["height"];

  /**
   * Offset of the inbox from the trigger button, in pixels.
   * Can be a single number or an object with main/cross axis.
   * @type {OffsetOptions}
   * @default 8
   */
  offset?: FloatingUIProps["offset"];

  /**
   * Where to place the inbox relative to the trigger button.
   * E.g. 'bottom-end', 'top-start', etc.
   * @type {Placement}
   * @default bottom-start
   */
  placement?: FloatingUIProps["placement"];

  /**
   * Whether the inbox should be open by default.
   * @default false
   */
  defaultOpen?: FloatingUIProps["defaultOpen"];

  /**
   * Controlled open state. When provided, component becomes controlled
   * and will not close on outside click or Escape by itself.
   */
  open?: FloatingUIProps["open"];

  /**
   * Called whenever the user intends to change the open state.
   * Receives the next state and the reason: 'toggle' | 'outside' | 'escape'.
   */
  onOpenChange?: FloatingUIProps["onOpenChange"];

  /**
   * Called when a notification item is clicked.
   * Call `event.preventDefault()` to prevent the default behavior.
   */
  onNotificationClick?: (
    event: Event,
    detail: {
      notification: Notification;
    }
  ) => void;

  /**
   * The component used to trigger the inbox, typically a bell icon.
   * It will receive `onClick` and `ref` props.
   * @type {Component}
   * @default InboxButton
   */
  ButtonComponent?: FloatingUIProps["TriggerComponent"];

  /**
   * The inbox component to render inside the floating panel.
   * Defaults to `<Inbox />` if not provided.
   * @type {Component}
   * @default Inbox
   */
  InboxComponent?: FloatingUIProps["FloatingComponent"];
};
import type { Notification } from "magicbell-js/user-client";
import Inbox from "./inbox.js";
import type { FloatingUIProps } from "./internal/components/floating-ui.js";
import FloatingUI from "./internal/components/floating-ui.js";
import InboxButton from "./internal/components/inbox--button.js";

function FloatingInbox(props: FloatingInboxProps) {
  const [When, setWhen] = useState(() => null);

  return (
    <FloatingUI
      placement={props.placement}
      TriggerComponent={props.ButtonComponent || InboxButton}
      FloatingComponent={props.InboxComponent || Inbox}
      floatingComponentProps={{
        onNotificationClick: props.onNotificationClick,
      }}
      height={props.height}
      width={props.width}
      offset={props.offset}
      defaultOpen={props.defaultOpen}
      open={props.open}
      onOpenChange={(details, event) => props.onOpenChange?.(details, event)}
    />
  );
}

export default FloatingInbox;

"use client";
import * as React from "react";
import { useState, useContext, useRef, useEffect } from "react";

/**
 * A notification inbox component that displays a list of notifications for the current user.
 *
 * Supports pagination, read/unread states, and customizable rendering of notification items.
 * Can be embedded directly in a page or used in combination with floating UIs using FloatingInbox.
 *
 * @event { notification: Notification } mb-notification-click - Emitted when a notification item is clicked. Call event.preventDefault() to stop default navigation.
 **/
type Props = {
  /**
   * Passed through by a parent component when rendering the FloatingInbox
   * @internal
   * @default false
   */
  floating?: boolean;
  /**
   * Set the height of the inbox.
   * @default 400
   */
  height?: number;
  /**
   * Estimated item height. It gets measured after mount, but it helps to estimate
   * this to limit layout shift.
   * @default 50
   */
  itemHeight?: number;
  /**
   * Component to use as Notification Item. The component receives two props;
   * `index: number` and `data: Notification`.
   * @type {Component}
   */
  ItemComponent?: any;

  /**
   * Called when a notification item is clicked.
   * Call `event.preventDefault()` to prevent the default behavior.
   */
  onNotificationClick?: (
    event: Event,
    detail: {
      notification: Notification;
    }
  ) => void;
};
import type { Notification } from "magicbell-js/user-client";
import type { Observer } from "tinycoll";
import { UserPreferences } from "./index.js";
import EmptyState from "./internal/components/inbox--empty-state.js";
import InboxFooter from "./internal/components/inbox--footer.js";
import InboxItem from "./internal/components/inbox--item.js";
import VirtualList from "./internal/components/virtual-list/virtual-list.js";
import MagicBellContext from "./internal/context/magicbell.context.js";
import CloseIcon from "./internal/icons/close-icon.js";
import GearIcon from "./internal/icons/gear-icon.js";
import ListCheckMarkIcon from "./internal/icons/list-checkmark-icon.js";

function Inbox(props: Props) {
  const headerRef = useRef<HTMLDivElement>(null);
  const footerRef = useRef<HTMLDivElement>(null);
  const [_notifications, set_notifications] = useState(() => []);

  const [_observer, set_observer] = useState(() => null);

  const [_ready, set_ready] = useState(() => false);

  const [_mounted, set_mounted] = useState(() => false);

  const [_view, set_view] = useState(() => "inbox");

  const [_headerHeight, set_headerHeight] = useState(() => 0);

  const [_footerHeight, set_footerHeight] = useState(() => 0);

  const [_defaults, set_defaults] = useState(() => ({
    floating: false,
    height: 400,
    itemHeight: 50,
  }));

  function getHeight() {
    const h = props.height || _defaults.height;
    return h - _headerHeight - _footerHeight;
  }

  function getItemHeight() {
    return props.itemHeight || _defaults.itemHeight;
  }

  function getNotifications() {
    return _notifications;
  }

  function getIsEmpty() {
    return _ready && _notifications.length === 0;
  }

  function getTitle() {
    return _view === "preferences" ? "Preferences" : "Notifications";
  }

  function toggleView(event) {
    event.stopPropagation();
    set_view(_view === "preferences" ? "inbox" : "preferences");
  }

  const [lite, setLite] = useState(() => null);

  const ctx = useContext(MagicBellContext);

  useEffect(() => {
    set_mounted(true);
    set_observer(
      ctx.notifications
        .find(
          {
            discardedAt: null,
            archivedAt: null,
          },
          {
            sort: {
              sentAt: -1,
            },
          }
        )
        .watch((docs) => {
          set_ready(true);
          set_notifications(docs);
        })
    );
  }, []);
  useEffect(() => {
    // we retrieve the heights in a RAF, because React otherwise
    // returns 0 for the offsetHeight of the header/footer
    requestAnimationFrame(() => {
      if (!_mounted) return;
      const headerHeight = headerRef.current?.offsetHeight || 0;
      if (headerHeight && _headerHeight !== headerHeight) {
        set_headerHeight(headerHeight);
      }
      const footerHeight = footerRef.current?.offsetHeight || 0;
      if (footerHeight && _footerHeight !== footerHeight) {
        set_footerHeight(footerHeight);
      }
    });
  }, [_mounted]);
  useEffect(() => {
    return () => {
      set_mounted(false);
      _observer?.stop();
    };
  }, []);

  return (
    <>
      <div
        className="magicbell--inbox div-40be798e"
        data-floating={props.floating || null}
        data-count={getNotifications().length}
      >
        <div className="magicbell--inbox-header" ref={headerRef}>
          <div className="magicbell--inbox-header--title">{getTitle()}</div>
          <div className="magicbell--inbox-header--actions">
            {_view === "inbox" ? (
              <button
                title="Mark all as read"
                className="magicbell--inbox-header--button"
                onClick={(event) => ctx.notifications.markAllRead()}
              >
                <ListCheckMarkIcon />
              </button>
            ) : null}
            {_view === "inbox" ? (
              <button
                title="Preferences"
                className="magicbell--inbox-header--button"
                onClick={(event) => toggleView(event)}
              >
                <GearIcon />
              </button>
            ) : null}
            {_view === "preferences" ? (
              <button
                title="Preferences"
                className="magicbell--inbox-header--button"
                onClick={(event) => toggleView(event)}
              >
                <CloseIcon />
              </button>
            ) : null}
          </div>
        </div>
        {_view === "preferences" ? (
          <div
            style={{
              height: `${getHeight()}px`,
            }}
          >
            <UserPreferences />
          </div>
        ) : null}
        {_view === "inbox" && !getIsEmpty() ? (
          <VirtualList
            listHeight={getHeight()}
            items={getNotifications()}
            itemCount={getNotifications().length}
            itemHeight={getItemHeight()}
            ItemComponent={props.ItemComponent || InboxItem}
            itemComponentProps={{
              onNotificationClick: props.onNotificationClick,
            }}
            onEndReached={(event) => ctx.notifications.fetchMore()}
          />
        ) : null}
        {_view === "inbox" && getIsEmpty() ? (
          <EmptyState height={getHeight()} />
        ) : null}
        <div className="magicbell--inbox-footer" ref={footerRef}>
          <InboxFooter />
        </div>
      </div>
      <style>{`.div-40be798e {
  height: 100%;
  width: 100%;
}`}</style>
    </>
  );
}

export default Inbox;

"use client";
import * as React from "react";
import { useContext } from "react";

type Props = {
  index: number;
  data: Notification;
  onNotificationClick?: (
    event: Event,
    detail: {
      notification: Notification;
    }
  ) => void;
};
import type { Notification } from "magicbell-js/user-client";
import MagicBellContext from "../context/magicbell.context.js";
import { formatDate } from "../lib/date.js";
import FloatingUI from "./floating-ui.js";
import Menu from "./inbox--item--menu.js";
import MenuButton from "./menu-button.js";

function InboxItem(props: Props) {
  function getStatus() {
    if (props.data.archivedAt) return "archived";
    if (props.data.readAt) return "read";
    return "unread";
  }

  function handleClick(event: any) {
    if (event.defaultPrevented) return;
    const target = event.target as HTMLElement | null;
    if (!target) return;

    // ignore clicks inside the action menu
    if (target.closest(".magicbell--inbox-item--action")) return;
    const currentTarget = event.currentTarget as HTMLElement | null;
    const notificationEvent = new CustomEvent("mb-notification-click", {
      detail: {
        notification: props.data,
      },
      bubbles: true,
      composed: true,
      cancelable: true,
    });
    currentTarget?.dispatchEvent(notificationEvent);
    if (notificationEvent.defaultPrevented) {
      event.preventDefault?.();
      return;
    }
    props.onNotificationClick?.(event, {
      notification: props.data,
    });
    if (event.defaultPrevented) return;

    // interacting with notification, so mark as read
    const markAsRead = ctx.notifications.markAsRead(props.data.id);
    const actionUrl = props.data?.actionUrl;
    if (!actionUrl) return;

    // do not open action-url when clicking on interactive elements inside notification content
    const contentElement = target.closest(".magicbell--inbox-item--content");
    if (contentElement) {
      const interactiveSelector =
        "a, button, input, select, textarea, label, [role='button'], [role='link'], [contenteditable='true']";
      if (target.closest(interactiveSelector)) return;
    }

    // We wait for the markAsRead before navigating to the new url, to prevent race conditions
    // between mark and read, and fetching new data on page reload. But let us not wait forever.
    const timeout = new Promise((resolve) => setTimeout(resolve, 250));
    Promise.race([markAsRead, timeout]).then(() =>
      window.location.assign(actionUrl)
    );
  }

  const ctx = useContext(MagicBellContext);

  return (
    <div
      className="magicbell--inbox-item"
      data-status={getStatus()}
      data-index={props.index}
      tabIndex={0}
      onClick={(event) => handleClick(event)}
    >
      <div
        className="magicbell--inbox-item--title"
        dangerouslySetInnerHTML={{ __html: props.data.title }}
      />
      <div className="magicbell--inbox-item--date">
        {formatDate(props.data.sentAt!)}
      </div>
      <div className="magicbell--inbox-item--action">
        <FloatingUI
          TriggerComponent={MenuButton}
          FloatingComponent={Menu}
          data={props.data}
          width={140}
        />
      </div>
      {props.data.content ? (
        <div
          className="magicbell--inbox-item--content"
          dangerouslySetInnerHTML={{ __html: props.data.content! }}
        />
      ) : null}
    </div>
  );
}

export default InboxItem;

"use client";
import * as React from "react";
import { useState, useRef, useEffect } from "react";

export type VirtualListProps = {
  listHeight: number;
  itemCount: number;
  itemHeight: number;
  ItemComponent: any;
  itemComponentProps?: any;
  overscanCount?: number;
  items: any[];
  onEndReached?: (event: null) => void;
};
import type { VirtualListNode } from "./virtual-list-manager.js";
import { VirtualListManager } from "./virtual-list-manager.js";

function VirtualList(props: VirtualListProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(() => []);

