  const cacheKey = [props.token, props.baseUrl || "", props.socketUrl || ""];
  const client = memo(["client", ...cacheKey], () => new Client({
    token: props.token,
    baseUrl: props.baseUrl
  }));
  const socket = memo(["socket", ...cacheKey], () => new RealtimeStore({
    client: client,
    socketUrl: props.socketUrl
  }));
  const notifications = memo(["notifications", ...cacheKey], () => new NotificationStore({
    client: client,
    socket: socket
  }));
  const ctx: MagicBellContext = {
    client,
    socket,
    notifications,
    sessionId: getSessionId()
  };
  setDebug("ctx", ctx);
  return ctx;
}

