import React, { useState, useEffect } from 'react';
import { MagicBellProvider, FloatingInbox, Inbox } from '@magicbell/react';
import CustomNotificationItem from './CustomNotificationItem';

function CustomInbox(props) {
  return <Inbox {...props} ItemComponent={CustomNotificationItem} />;
}

function App() {
  const [token, setToken] = useState(null);

  useEffect(() => {
    fetch('http://localhost:3001/token')
      .then((res) => res.json())
      .then((data) => {
        setToken(data.token);
      })
      .catch((err) => {
        console.error('Failed to fetch token:', err);
      });
  }, []);

  if (!token) {
    return <div>Loading...</div>;
  }

  return (
    <MagicBellProvider token={token}>
      <div style={{ padding: '20px' }}>
        <h1>MagicBell Notifications</h1>
        <FloatingInbox
          InboxComponent={CustomInbox}
        />
      </div>
    </MagicBellProvider>
  );
}

export default App;
